sql:
SELECT total_administered
FROM vaccine_uptake
WHERE uptake_date = '2023-01-02';

SELECT DISTINCT campaign_name
FROM vaccination_data
ORDER BY date_of_data DESC;

SELECT demographic_id, SUM(total_administered) AS total_vaccines_administered
FROM vaccine_uptake
GROUP BY demographic_id;

external_knowledge:
- Completed vaccination campaign: A vaccination campaign that has been finalized and is no longer active; 
- Fully vaccinated percentage: The ratio of fully vaccinated individuals to the total population, expressed as a percentage; 
- ROW_NUMBER() function: A SQL function that assigns a unique number to each row within a result set, based on a specified ordering; 
- Partitioning and ranking: SQL techniques used to divide a result set into partitions and assign a ranking to each row within each partition.

sql:
SELECT distribution_date, quantity_distributed
FROM vaccine_distributions
WHERE distribution_status = 'Completed' AND quantity_distributed > 2500;

SELECT vaccine_id, quantity_distributed
FROM vaccine_distributions
ORDER BY distribution_date ASC;

SELECT dhb_name, MAX(population) AS max_population
FROM health_districts
GROUP BY dhb_name;
